/* js/ui/ModalManager.js */
class ModalManager {
  constructor(overlay, audio) {
    this.overlay = overlay;
    this.audio = audio;
    this.resolve = null;
  }

  open({ title = "", body = "", actions = [] }) {
    this.close(null, false);
    this.overlay.classList.add("is-open");
    this.overlay.setAttribute("aria-hidden", "false");

    const modal = document.createElement("section");
    modal.className = "modal";
    modal.setAttribute("role", "dialog");
    modal.setAttribute("aria-modal", "true");

    const bodyNode = body instanceof HTMLElement ? body : document.createElement("div");
    if (!(body instanceof HTMLElement)) {
      bodyNode.innerHTML = body;
    }

    modal.innerHTML = `
      <header class="modal-header">
        <h2 class="section-title">${title}</h2>
        <button class="modal-close" type="button" aria-label="關閉">x</button>
      </header>
    `;
    const content = document.createElement("div");
    content.className = "modal-body";
    content.append(bodyNode);

    const footer = document.createElement("footer");
    footer.className = "modal-footer";
    for (const action of actions) {
      const button = document.createElement("button");
      button.type = "button";
      button.className = action.className ?? "btn";
      button.textContent = action.label;
      button.dataset.action = action.value;
      button.disabled = Boolean(action.disabled);
      footer.append(button);
    }

    modal.append(content, footer);
    this.overlay.append(modal);

    modal.querySelector(".modal-close").addEventListener("click", () => this.close(null));
    footer.addEventListener("click", (event) => {
      const button = event.target.closest("[data-action]");
      if (!button) return;
      this.audio?.playSfx("buttonClick");
      this.close(button.dataset.action);
    });
    this.overlay.addEventListener("click", this.handleBackdrop);
    document.addEventListener("keydown", this.handleEscape);
    modal.querySelector("button:not(:disabled)")?.focus();

    return new Promise((resolve) => {
      this.resolve = resolve;
    });
  }

  handleBackdrop = (event) => {
    if (event.target === this.overlay) {
      this.close(null);
    }
  };

  handleEscape = (event) => {
    if (event.key === "Escape") {
      this.close(null);
    }
  };

  close(value = null, shouldResolve = true) {
    document.removeEventListener("keydown", this.handleEscape);
    this.overlay.removeEventListener("click", this.handleBackdrop);
    this.overlay.classList.remove("is-open");
    this.overlay.setAttribute("aria-hidden", "true");
    this.overlay.innerHTML = "";
    if (shouldResolve && this.resolve) {
      const resolve = this.resolve;
      this.resolve = null;
      resolve(value);
    }
  }
}


/* js/ui/KeyboardVisualizer.js */
const ROWS = [
  ["Q", "W", "E", "R", "T", "Y", "U", "I", "O", "P"],
  ["A", "S", "D", "F", "G", "H", "J", "K", "L"],
  ["Z", "X", "C", "V", "B", "N", "M"],
];

class KeyboardVisualizer {
  constructor(container) {
    this.container = container;
    this.keys = new Map();
  }

  render() {
    this.container.innerHTML = "";
    this.keys.clear();
    this.container.className = "keyboard";
    for (const row of ROWS) {
      const rowEl = document.createElement("div");
      rowEl.className = "keyboard-row";
      for (const key of row) {
        const el = document.createElement("span");
        el.className = "key";
        el.textContent = key;
        rowEl.append(el);
        this.keys.set(key, el);
      }
      this.container.append(rowEl);
    }
  }

  flash(key) {
    const el = this.keys.get(String(key).toUpperCase());
    if (!el) return;
    el.classList.add("is-active");
    window.setTimeout(() => el.classList.remove("is-active"), 110);
  }

  setNext(key) {
    for (const el of this.keys.values()) {
      el.classList.remove("is-next");
    }
    const el = this.keys.get(String(key ?? "").toUpperCase());
    el?.classList.add("is-next");
  }
}


/* js/ui/AnimationManager.js */
class AnimationManager {
  static pulse(element) {
    if (!element) return;
    element.style.animation = "none";
    element.offsetHeight;
    element.style.animation = "pop 160ms ease";
  }

  static shake(element) {
    if (!element) return;
    element.style.animation = "none";
    element.offsetHeight;
    element.style.animation = "shake 200ms ease";
  }
}


/* js/audio/SFXPool.js */
class SFXPool {
  constructor(src, poolSize = 5) {
    this.pool = Array.from({ length: poolSize }, () => {
      const audio = new Audio(src);
      audio.preload = "auto";
      return audio;
    });
    this.index = 0;
  }

  play(volume = 1) {
    const audio = this.pool[this.index % this.pool.length];
    audio.currentTime = 0;
    audio.volume = volume;
    audio.play().catch(() => {});
    this.index += 1;
  }
}


/* js/audio/BGMPlayer.js */
const PATTERNS = {
  menu: [220, 277, 330, 415],
  game: [196, 247, 294, 370],
  result: [262, 330, 392, 523],
  tutorial: [174, 220, 262, 330],
  settings: [147, 196, 247, 294],
};

class BGMPlayer {
  constructor(getContext, getVolume) {
    this.getContext = getContext;
    this.getVolume = getVolume;
    this.intervalId = null;
    this.step = 0;
    this.pattern = PATTERNS.menu;
  }

  start(screenName = "menu", difficulty = "normal") {
    this.stop();
    const key = screenName === "game" ? "game" : screenName;
    this.pattern = PATTERNS[key] ?? PATTERNS.menu;
    if (difficulty === "hell") this.pattern = [110, 165, 220, 311, 392];
    if (difficulty === "hard") this.pattern = [146, 220, 293, 440];
    this.intervalId = window.setInterval(() => this.playStep(), screenName === "game" ? 480 : 760);
    this.playStep();
  }

  playStep() {
    const volume = this.getVolume();
    if (volume <= 0) return;
    const context = this.getContext();
    if (!context) return;
    const frequency = this.pattern[this.step % this.pattern.length];
    this.step += 1;

    const oscillator = context.createOscillator();
    const gain = context.createGain();
    oscillator.type = "triangle";
    oscillator.frequency.value = frequency;
    gain.gain.setValueAtTime(0, context.currentTime);
    gain.gain.linearRampToValueAtTime(volume * 0.04, context.currentTime + 0.02);
    gain.gain.exponentialRampToValueAtTime(0.0001, context.currentTime + 0.36);
    oscillator.connect(gain).connect(context.destination);
    oscillator.start();
    oscillator.stop(context.currentTime + 0.38);
  }

  stop() {
    if (this.intervalId) {
      window.clearInterval(this.intervalId);
      this.intervalId = null;
    }
  }
}


/* js/audio/AudioManager.js */

const SFX = {
  keyCorrect: [660, 0.05, "sine"],
  keyWrong: [130, 0.11, "sawtooth"],
  wordComplete: [880, 0.12, "triangle"],
  combo: [1046, 0.18, "square"],
  comboBreak: [98, 0.18, "sawtooth"],
  levelUp: [1174, 0.16, "triangle"],
  countdown: [440, 0.09, "sine"],
  gameStart: [784, 0.22, "triangle"],
  gameOver: [165, 0.3, "sawtooth"],
  newRecord: [1318, 0.32, "triangle"],
  buttonClick: [520, 0.06, "square"],
  buttonHover: [390, 0.04, "sine"],
  screenIn: [300, 0.08, "triangle"],
  screenOut: [220, 0.08, "triangle"],
};

class AudioManager {
  constructor(state) {
    this.state = state;
    this.context = null;
    this.unlocked = false;
    this.muted = false;
    this.lastScreenName = "menu";
    this.lastDifficulty = this.state.getSettings().difficulty;
    this.bgm = new BGMPlayer(() => this.context, () => this.bgmVolume());
  }

  initGestureUnlock() {
    const unlock = () => {
      this.ensureContext();
      if (this.context?.state === "suspended") {
        this.context.resume().catch(() => {});
      }
      this.unlocked = true;
      document.removeEventListener("pointerdown", unlock);
      document.removeEventListener("keydown", unlock);
    };
    document.addEventListener("pointerdown", unlock, { once: true });
    document.addEventListener("keydown", unlock, { once: true });
  }

  ensureContext() {
    if (!this.context) {
      const AudioContextClass = window.AudioContext || window.webkitAudioContext;
      if (!AudioContextClass) return null;
      this.context = new AudioContextClass();
    }
    return this.context;
  }

  refreshSettings() {
    if (this.muted) return;
    this.bgm.playStep();
  }

  masterVolume() {
    return this.muted ? 0 : this.state.getSettings().masterVolume / 100;
  }

  bgmVolume() {
    const settings = this.state.getSettings();
    return this.masterVolume() * (settings.bgmVolume / 100);
  }

  sfxVolume() {
    const settings = this.state.getSettings();
    return this.masterVolume() * (settings.sfxVolume / 100);
  }

  playBgm(screenName, difficulty) {
    this.lastScreenName = screenName;
    this.lastDifficulty = difficulty;
    const settings = this.state.getSettings();
    if (this.muted) {
      this.bgm.stop();
      return;
    }
    if (!settings.persistBGM && screenName !== "game") {
      this.bgm.stop();
      return;
    }
    if (!this.unlocked) return;
    this.bgm.start(screenName, difficulty);
  }

  stopBgm() {
    this.bgm.stop();
  }

  toggleMute() {
    this.muted = !this.muted;
    if (this.muted) {
      this.stopBgm();
    } else {
      this.playBgm(this.lastScreenName, this.lastDifficulty);
    }
  }

  playSfx(name) {
    const [frequency, duration, type] = SFX[name] ?? SFX.buttonClick;
    const volume = this.sfxVolume();
    if (!this.unlocked || volume <= 0) return;
    const context = this.ensureContext();
    if (!context) return;
    const oscillator = context.createOscillator();
    const gain = context.createGain();
    oscillator.type = type;
    oscillator.frequency.value = frequency;
    gain.gain.setValueAtTime(0, context.currentTime);
    gain.gain.linearRampToValueAtTime(volume * 0.18, context.currentTime + 0.01);
    gain.gain.exponentialRampToValueAtTime(0.0001, context.currentTime + duration);
    oscillator.connect(gain).connect(context.destination);
    oscillator.start();
    oscillator.stop(context.currentTime + duration + 0.02);
  }
}


/* js/core/EventBus.js */
class EventBus {
  constructor() {
    this.listeners = new Map();
  }

  on(eventName, callback) {
    const listeners = this.listeners.get(eventName) ?? new Set();
    listeners.add(callback);
    this.listeners.set(eventName, listeners);
    return () => this.off(eventName, callback);
  }

  off(eventName, callback) {
    this.listeners.get(eventName)?.delete(callback);
  }

  emit(eventName, payload) {
    for (const callback of this.listeners.get(eventName) ?? []) {
      callback(payload);
    }
  }
}


/* js/core/Router.js */
class Router {
  constructor(container) {
    this.container = container;
    this.screens = new Map();
    this.current = null;
    this.currentName = "";
  }

  register(name, screen) {
    this.screens.set(name, screen);
  }

  async navigate(name, params = {}) {
    const nextScreen = this.screens.get(name);
    if (!nextScreen) {
      throw new Error(`Unknown screen: ${name}`);
    }

    if (this.current?.unmount) {
      this.current.unmount();
    }

    this.current = nextScreen;
    this.currentName = name;
    this.container.innerHTML = "";
    const element = await nextScreen.mount(params);
    this.container.append(element);
    requestAnimationFrame(() => {
      element.querySelector("[data-autofocus]")?.focus();
    });
  }
}


/* js/core/StateManager.js */


const DEFAULT_SETTINGS = {
  theme: "default",
  fontSize: "medium",
  masterVolume: 100,
  bgmVolume: 70,
  sfxVolume: 75,
  sfxSkin: "standard",
  showVirtualKeyboard: true,
  persistBGM: true,
  showLiveWPM: true,
  enableShakeOnError: true,
  enableComboEffect: true,
  animation: true,
  language: "en",
  difficulty: "normal",
  gameDuration: 60,
};

const DEFAULT_RECORDS = {
  easy: { wpm: 0, accuracy: 0, score: 0, date: null },
  normal: { wpm: 0, accuracy: 0, score: 0, date: null },
  hard: { wpm: 0, accuracy: 0, score: 0, date: null },
  hell: { wpm: 0, accuracy: 0, score: 0, date: null },
};

class StateManager {
  constructor(storage = new Storage("typingGame_")) {
    this.storage = storage;
    this.settings = this.normalizeSettings(this.storage.get("settings", DEFAULT_SETTINGS));
    this.currentResult = null;
    this.lastGameOptions = null;
  }

  normalizeSettings(settings) {
    return {
      ...DEFAULT_SETTINGS,
      ...settings,
      masterVolume: clamp(Number(settings?.masterVolume ?? DEFAULT_SETTINGS.masterVolume), 0, 100),
      bgmVolume: clamp(Number(settings?.bgmVolume ?? DEFAULT_SETTINGS.bgmVolume), 0, 100),
      sfxVolume: clamp(Number(settings?.sfxVolume ?? DEFAULT_SETTINGS.sfxVolume), 0, 100),
      gameDuration: Number(settings?.gameDuration ?? DEFAULT_SETTINGS.gameDuration),
      showVirtualKeyboard: Boolean(settings?.showVirtualKeyboard ?? DEFAULT_SETTINGS.showVirtualKeyboard),
      persistBGM: Boolean(settings?.persistBGM ?? DEFAULT_SETTINGS.persistBGM),
      showLiveWPM: Boolean(settings?.showLiveWPM ?? DEFAULT_SETTINGS.showLiveWPM),
      enableShakeOnError: Boolean(settings?.enableShakeOnError ?? DEFAULT_SETTINGS.enableShakeOnError),
      enableComboEffect: Boolean(settings?.enableComboEffect ?? DEFAULT_SETTINGS.enableComboEffect),
      animation: Boolean(settings?.animation ?? DEFAULT_SETTINGS.animation),
    };
  }

  getSettings() {
    return { ...this.settings };
  }

  updateSettings(patch) {
    this.settings = this.normalizeSettings({ ...this.settings, ...patch });
    this.storage.set("settings", this.settings);
    return this.getSettings();
  }

  getSavedGame() {
    return this.storage.get("savedGame", null);
  }

  saveGame(snapshot) {
    if (!snapshot) return;
    this.storage.set("savedGame", {
      ...snapshot,
      savedAt: new Date().toISOString(),
    });
  }

  clearSavedGame() {
    this.storage.remove("savedGame");
  }

  getHistory() {
    return this.storage.get("history", []);
  }

  getRecords() {
    return { ...DEFAULT_RECORDS, ...this.storage.get("records", DEFAULT_RECORDS) };
  }

  setCurrentResult(result) {
    this.currentResult = result;
  }

  pushHistory(result) {
    const entry = {
      date: new Date().toISOString(),
      wpm: result.wpm,
      accuracy: result.accuracy,
      score: result.score,
      wordsCompleted: result.wordsCompleted,
      maxCombo: result.maxCombo,
      difficulty: result.settings.difficulty,
      language: result.settings.language,
      duration: result.settings.gameDuration,
    };
    const history = [entry, ...this.getHistory()].slice(0, 50);
    this.storage.set("history", history);

    const records = this.getRecords();
    const current = records[entry.difficulty] ?? DEFAULT_RECORDS[entry.difficulty];
    const isNewRecord = entry.wpm > current.wpm || (entry.wpm === current.wpm && entry.score > current.score);
    if (isNewRecord) {
      records[entry.difficulty] = {
        wpm: entry.wpm,
        accuracy: entry.accuracy,
        score: entry.score,
        date: entry.date,
      };
      this.storage.set("records", records);
    }
    return { entry, isNewRecord };
  }

  resetRecords() {
    this.storage.set("records", DEFAULT_RECORDS);
    this.storage.set("history", []);
  }

  resetAll() {
    this.storage.clear();
    this.settings = { ...DEFAULT_SETTINGS };
    this.currentResult = null;
  }

  exportData() {
    return {
      settings: this.getSettings(),
      savedGame: this.getSavedGame(),
      history: this.getHistory(),
      records: this.getRecords(),
      exportedAt: new Date().toISOString(),
    };
  }

  importData(payload) {
    if (!payload || typeof payload !== "object") {
      throw new Error("匯入資料格式不正確");
    }
    if (payload.settings) {
      this.updateSettings(payload.settings);
    }
    if (Array.isArray(payload.history)) {
      this.storage.set("history", payload.history.slice(0, 50));
    }
    if (payload.records) {
      this.storage.set("records", { ...DEFAULT_RECORDS, ...payload.records });
    }
    if (payload.savedGame) {
      this.saveGame(payload.savedGame);
    }
  }
}


/* js/screens/MenuScreen.js */


const LANGUAGE_LABELS = {
  en: "English",
  zh: "中文",
  num: "數字",
  mixed: "混合",
  hira: "平假名",
  kata: "片假名",
};

const LANGUAGE_DESCRIPTIONS = {
  hira: "只能輸入日文假名，羅馬拼音不會被接受",
  kata: "只能輸入日文片假名，羅馬拼音不會被接受",
};

const DIFFICULTY_DESCRIPTIONS = {
  easy: "慢速練習，適合暖身",
  normal: "標準速度與計分",
  hard: "更高倍率，會混入變形字",
  hell: "高倍率、高懲罰與突發字型",
};

const DURATION_LABELS = {
  60: "60 秒",
  120: "120 秒",
  0: "無限模式",
};

class MenuScreen {
  constructor(app) {
    this.app = app;
    this.root = null;
  }

  mount() {
    const settings = this.app.state.getSettings();
    const savedGame = this.app.state.getSavedGame();
    const records = this.app.state.getRecords();
    const bestRecord = Object.entries(records)
      .sort(([, a], [, b]) => b.wpm - a.wpm)[0];

    this.root = document.createElement("section");
    this.root.id = "menu";
    this.root.className = "screen menu-screen";
    this.root.innerHTML = `
      <div class="menu-hero">
        <section class="panel brand-panel">
          <svg class="logo-mark" viewBox="0 0 760 210" role="img" aria-label="Typing Master">
            <rect x="24" y="26" width="712" height="156" rx="8" fill="none" stroke="currentColor" stroke-width="5" opacity="0.55"></rect>
            <path d="M86 146 L116 68 L148 146 M99 116 H135" fill="none" stroke="currentColor" stroke-width="12" stroke-linecap="round" stroke-linejoin="round"></path>
            <text x="190" y="106" fill="currentColor" font-size="54">TYPING</text>
            <text x="190" y="158" fill="currentColor" font-size="42" opacity="0.78">MASTER</text>
            <path d="M615 60 h64 v36 h-64 z M590 114 h104 v36 H590 z" fill="currentColor" opacity="0.2"></path>
          </svg>
          <div>
            <h1 class="display-title">Typing Master</h1>
            <p class="menu-copy">純前端打字訓練遊戲。選擇語言、難度與時間，透過 WPM、準確率、Combo 與本機紀錄追蹤進步。</p>
          </div>
          <div class="toolbar">
            <span class="combo-badge">Theme: ${settings.theme}</span>
            <span class="combo-badge">Mode: ${DifficultyManager.label(settings.difficulty)}</span>
          </div>
        </section>

        <aside class="menu-side">
          <section class="panel panel-pad menu-actions" aria-label="主選單">
            <button class="btn btn-primary" type="button" data-action="start" data-autofocus>開始遊戲</button>
            <button class="btn" type="button" data-action="resume" ${savedGame ? "" : "disabled"}>繼續遊戲</button>
            <button class="btn" type="button" data-action="tutorial">教學</button>
            <button class="btn" type="button" data-action="settings">設定</button>
            <button class="btn btn-ghost" type="button" data-action="mute">${this.app.audio.muted ? "恢復音效" : "靜音"}</button>
          </section>

          <section class="panel panel-pad">
            <h2 class="section-title">最佳紀錄</h2>
            <div class="record-list" style="margin-top: var(--space-4)">
              ${this.renderRecord(bestRecord)}
              ${savedGame ? `<div class="record-row"><span>已儲存進度</span><strong>${DifficultyManager.label(savedGame.settings?.difficulty)}</strong></div>` : `<p class="muted">尚無可繼續的遊戲。</p>`}
            </div>
          </section>
        </aside>
      </div>
    `;

    this.root.addEventListener("click", this.handleClick);
    return this.root;
  }

  renderRecord(recordPair) {
    if (!recordPair) return `<p class="muted">完成一場遊戲後會建立紀錄。</p>`;
    const [difficulty, record] = recordPair;
    if (!record?.wpm) return `<p class="muted">完成一場遊戲後會建立紀錄。</p>`;
    return `
      <div class="record-row">
        <span>${DifficultyManager.label(difficulty)} / ${formatDate(record.date)}</span>
        <strong class="mono">${record.wpm} WPM</strong>
      </div>
      <div class="record-row">
        <span>準確率</span>
        <strong class="mono">${record.accuracy}%</strong>
      </div>
      <div class="record-row">
        <span>分數</span>
        <strong class="mono">${record.score}</strong>
      </div>
    `;
  }

  handleClick = async (event) => {
    const button = event.target.closest("[data-action]");
    if (!button) return;
    this.app.audio.playSfx("buttonClick");
    const action = button.dataset.action;
    if (action === "start") {
      await this.openStartModal();
    }
    if (action === "resume") {
      const savedGame = this.app.state.getSavedGame();
      if (!savedGame) return;
      this.app.applySettings(savedGame.settings ?? {});
      this.app.go("game", { settings: this.app.state.getSettings(), snapshot: savedGame });
    }
    if (action === "tutorial") this.app.go("tutorial");
    if (action === "settings") this.app.go("settings");
    if (action === "mute") {
      this.app.audio.toggleMute();
      button.textContent = this.app.audio.muted ? "恢復音效" : "靜音";
    }
  };

  async openStartModal() {
    const selected = this.app.state.getSettings();
    const body = document.createElement("div");
    body.className = "start-options";
    body.innerHTML = `
      ${this.renderChoices("language", "語言", LANGUAGE_LABELS, selected.language, LANGUAGE_DESCRIPTIONS)}
      ${this.renderChoices("difficulty", "難度", {
        easy: "Easy",
        normal: "Normal",
        hard: "Hard",
        hell: "Hell",
      }, selected.difficulty, DIFFICULTY_DESCRIPTIONS)}
      ${this.renderChoices("gameDuration", "時間", DURATION_LABELS, selected.gameDuration)}
    `;

    body.addEventListener("click", (event) => {
      const choice = event.target.closest("[data-choice]");
      if (!choice) return;
      const group = choice.dataset.group;
      const value = group === "gameDuration" ? Number(choice.dataset.choice) : choice.dataset.choice;
      selected[group] = value;
      for (const item of body.querySelectorAll(`[data-group="${group}"]`)) {
        item.setAttribute("aria-pressed", String(item === choice));
      }
    });

    const result = await this.app.openModal({
      title: "開始設定",
      body,
      actions: [
        { label: "取消", value: "cancel", className: "btn btn-ghost" },
        { label: "開始", value: "start", className: "btn btn-primary" },
      ],
    });

    if (result === "start") {
      this.app.state.clearSavedGame();
      this.app.applySettings(selected);
      this.app.state.lastGameOptions = { ...selected };
      this.app.go("game", { settings: this.app.state.getSettings() });
    }
  }

  renderChoices(group, label, choices, selectedValue, descriptions = {}) {
    const entries = Object.entries(choices);
    return `
      <div class="option-group">
        <h3 class="section-title">${label}</h3>
        <div class="choice-grid">
          ${entries.map(([value, text]) => `
            <button class="choice-card" type="button" data-group="${group}" data-choice="${value}" aria-pressed="${String(value == selectedValue)}">
              <strong>${text}</strong>
              ${descriptions[value] ? `<small>${descriptions[value]}</small>` : ""}
            </button>
          `).join("")}
        </div>
      </div>
    `;
  }

  unmount() {
    this.root?.removeEventListener("click", this.handleClick);
  }
}


/* js/screens/GameScreen.js */





class GameScreen {
  constructor(app) {
    this.app = app;
    this.root = null;
    this.engine = null;
    this.input = null;
    this.keyboard = null;
    this.cleanup = [];
    this.lastAutoSave = 0;
    this.paused = false;
  }

  async mount({ settings = null, snapshot = null } = {}) {
    const activeSettings = { ...this.app.state.getSettings(), ...(settings ?? snapshot?.settings ?? {}) };
    const words = await this.app.words.load(activeSettings.language);
    this.root = document.createElement("section");
    this.root.id = "game";
    this.root.className = "screen game-screen";
    this.root.innerHTML = `
      <header class="panel game-hud">
        <div class="hud-stack">
          <strong>${DifficultyManager.label(activeSettings.difficulty)} / ${this.languageLabel(activeSettings.language)}</strong>
          <span class="muted">${activeSettings.gameDuration > 0 ? `${activeSettings.gameDuration} 秒挑戰` : "無限模式"}</span>
        </div>
        <div class="hud-stack">
          <div class="hud-line">
            <span>時間 <strong class="mono" data-field="time">--:--</strong></span>
            <span>進度</span>
          </div>
          <div class="progress" aria-label="時間進度"><span data-field="progress"></span></div>
        </div>
        <div class="hud-line" style="justify-content: flex-end">
          <span>分數 <strong class="mono" data-field="score">0</strong></span>
          <span>WPM <strong class="mono" data-field="wpm">0</strong></span>
          <button class="btn icon-btn" type="button" data-action="pause" aria-label="暫停">II</button>
        </div>
      </header>

      <section class="panel game-stage" aria-label="遊戲區">
        <div class="score-grid" style="width: min(720px, 100%)">
          <div class="score-tile"><span class="score-label">準確率</span><strong class="score-value" data-field="accuracy">100%</strong></div>
          <div class="score-tile"><span class="score-label">連擊</span><strong class="score-value" data-field="combo">0</strong></div>
          <div class="score-tile"><span class="score-label">完成字</span><strong class="score-value" data-field="words">0</strong></div>
          <div class="score-tile"><span class="score-label">錯誤</span><strong class="score-value" data-field="errors">0</strong></div>
        </div>
        <div class="target-word" data-field="word"></div>
        <input class="input-preview game-input" data-field="hiddenInput" type="text" autocomplete="off" autocapitalize="none" spellcheck="false" inputmode="text" lang="${this.inputLang(activeSettings.language)}" placeholder="準備開始" aria-label="打字輸入">
        <div class="combo-badge" data-field="comboBadge">Combo x0</div>
      </section>

      <footer class="game-footer">
        <div data-field="keyboard"></div>
        <p class="muted" style="text-align: center">Esc 暫停，Backspace 修正，Tab 回到輸入區。</p>
      </footer>
    `;

    this.input = this.root.querySelector("[data-field='hiddenInput']");
    this.keyboard = new KeyboardVisualizer(this.root.querySelector("[data-field='keyboard']"));
    if (activeSettings.showVirtualKeyboard) {
      this.keyboard.render();
    }

    this.engine = new GameEngine({
      settings: activeSettings,
      words,
      snapshot,
      audio: this.app.audio,
      onUpdate: (view) => this.updateView(view),
      onFinish: (result) => this.finish(result),
      onCombo: (milestone) => this.handleCombo(milestone),
    });

    this.bindEvents();
    this.updateView(this.engine.getViewState());

    if (snapshot) {
      this.engine.start();
      this.focusInput();
      this.app.showToast("已載入儲存進度", "success");
    } else {
      this.runCountdown().then(() => {
        this.app.audio.playSfx("gameStart");
        this.engine.start();
        this.focusInput();
      });
    }

    return this.root;
  }

  bindEvents() {
    this.root.addEventListener("click", this.handleClick);
    this.input.addEventListener("input", this.handleInput);
    this.input.addEventListener("compositionstart", this.handleCompositionStart);
    this.input.addEventListener("compositionend", this.handleCompositionEnd);
    document.addEventListener("keydown", this.handleKeydown);
    document.addEventListener("pointerdown", this.focusInput);
    window.addEventListener("beforeunload", this.saveBeforeUnload);
    this.cleanup.push(() => this.root?.removeEventListener("click", this.handleClick));
    this.cleanup.push(() => this.input?.removeEventListener("input", this.handleInput));
    this.cleanup.push(() => this.input?.removeEventListener("compositionstart", this.handleCompositionStart));
    this.cleanup.push(() => this.input?.removeEventListener("compositionend", this.handleCompositionEnd));
    this.cleanup.push(() => document.removeEventListener("keydown", this.handleKeydown));
    this.cleanup.push(() => document.removeEventListener("pointerdown", this.focusInput));
    this.cleanup.push(() => window.removeEventListener("beforeunload", this.saveBeforeUnload));
  }

  handleClick = (event) => {
    const action = event.target.closest("[data-action]")?.dataset.action;
    if (action === "pause") this.openPauseModal();
    this.focusInput();
  };

  handleCompositionStart = () => {
    this.composing = true;
  };

  handleCompositionEnd = () => {
    this.composing = false;
    this.handleInput();
  };

  handleInput = () => {
    if (this.composing || !this.engine) return;
    if (this.suppressNextInputEvent) {
      this.suppressNextInputEvent = false;
      this.input.value = this.engine.input;
      return;
    }
    const current = this.engine.input;
    const value = this.input.value;
    const currentChars = [...current];
    const valueChars = [...value];

    if (valueChars.length > currentChars.length) {
      const additions = valueChars.slice(currentChars.length);
      for (const char of additions) {
        if (this.shouldBlockRomaji(char)) {
          this.app.showToast("請切換日文輸入法輸入假名，羅馬拼音不會被接受。", "warning", 1800);
          continue;
        }
        this.engine.typeChar(char);
        this.keyboard?.flash(char);
      }
    } else if (valueChars.length < currentChars.length) {
      const count = currentChars.length - valueChars.length;
      for (let index = 0; index < count; index += 1) {
        this.engine.backspace();
      }
    }
    this.input.value = this.engine.input;
  };

  handleKeydown = (event) => {
    if (!this.engine) return;
    if (this.app.modal.overlay.classList.contains("is-open")) return;
    if (this.composing || event.isComposing || event.keyCode === 229) return;
    if (event.key === "Escape") {
      event.preventDefault();
      this.openPauseModal();
      return;
    }
    if (event.key === "Tab") {
      event.preventDefault();
      this.focusInput();
      return;
    }
    if ((event.ctrlKey || event.metaKey) && event.key.toLowerCase() === "r") {
      event.preventDefault();
      this.restart();
      return;
    }
    if (event.key === "Backspace") {
      if (document.activeElement === this.input) return;
      event.preventDefault();
      this.engine.backspace();
      this.input.value = this.engine.input;
      return;
    }
    if (this.shouldHandlePrintableKey(event)) {
      event.preventDefault();
      this.suppressNextInputEvent = true;
      window.setTimeout(() => {
        this.suppressNextInputEvent = false;
      }, 0);
      this.engine.typeChar(event.key);
      this.keyboard?.flash(event.key);
      this.input.value = this.engine.input;
    }
  };

  shouldHandlePrintableKey(event) {
    return (
      this.engine?.status === "playing" &&
      document.activeElement !== this.input &&
      !["zh", "mixed", "hira", "kata"].includes(this.engine.settings.language) &&
      !event.ctrlKey &&
      !event.metaKey &&
      !event.altKey &&
      !event.isComposing &&
      event.key.length === 1
    );
  }

  shouldBlockRomaji(char) {
    return ["hira", "kata"].includes(this.engine?.settings.language) && /[A-Za-z]/.test(char);
  }

  focusInput = () => {
    if (!this.input || this.app.modal.overlay.classList.contains("is-open")) return;
    this.input.focus({ preventScroll: true });
    window.scrollTo({ top: 0, left: 0, behavior: "auto" });
  };

  saveBeforeUnload = () => {
    if (this.engine && this.engine.status === "playing") {
      this.app.state.saveGame(this.engine.serialize());
    }
  };

  async runCountdown() {
    for (const label of ["3", "2", "1", "GO!"]) {
      this.app.audio.playSfx(label === "GO!" ? "gameStart" : "countdown");
      const overlay = document.createElement("div");
      overlay.className = "countdown";
      overlay.textContent = label;
      document.body.append(overlay);
      await new Promise((resolve) => window.setTimeout(resolve, 720));
      overlay.remove();
    }
  }

  updateView(view) {
    if (!this.root) return;
    this.root.querySelector("[data-field='time']").textContent = view.settings.gameDuration > 0 ? formatTime(view.timeRemaining) : formatTime(view.elapsedSeconds);
    this.root.querySelector("[data-field='progress']").style.setProperty("--progress", `${Math.max(0, Math.min(100, view.progress * 100))}%`);
    this.root.querySelector("[data-field='score']").textContent = String(view.score);
    this.root.querySelector("[data-field='wpm']").textContent = view.settings.showLiveWPM ? String(Math.round(view.wpm)) : "--";
    this.root.querySelector("[data-field='accuracy']").textContent = formatPercent(view.accuracy);
    this.root.querySelector("[data-field='combo']").textContent = String(view.combo);
    this.root.querySelector("[data-field='words']").textContent = String(view.wordsCompleted);
    this.root.querySelector("[data-field='errors']").textContent = String(view.wrongChars);
    this.root.querySelector("[data-field='comboBadge']").textContent = `Combo x${view.combo}`;
    this.renderWord(view.currentWord, view.input);
    this.input.placeholder = view.status === "playing" ? "輸入目前單字" : "準備開始";
    if (!this.composing) {
      this.input.value = view.input;
    }
    const nextKey = [...view.currentWord][[...view.input].length];
    this.keyboard?.setNext(nextKey);

    if (view.status === "playing" && view.elapsedSeconds - this.lastAutoSave > 5) {
      this.lastAutoSave = view.elapsedSeconds;
      this.app.state.saveGame(this.engine.serialize());
    }
  }

  renderWord(word, input) {
    const wordChars = [...word];
    const inputChars = [...input];
    const html = wordChars.map((char, index) => {
      let className = "";
      if (index < inputChars.length) className = inputChars[index] === char ? "correct" : "wrong";
      if (index === inputChars.length) className = `${className} cursor`.trim();
      return `<span class="${className}">${escapeHTML(char)}</span>`;
    }).join("");
    this.root.querySelector("[data-field='word']").innerHTML = html;
  }

  async openPauseModal() {
    if (this.paused || !this.engine || this.engine.status !== "playing") return;
    this.paused = true;
    this.engine.pause();
    this.app.state.saveGame(this.engine.serialize());
    const choice = await this.app.openModal({
      title: "暫停",
      body: `<p class="muted">目前進度已寫入 localStorage，可以返回主選單後繼續。</p>`,
      actions: [
        { label: "繼續", value: "resume", className: "btn btn-primary" },
        { label: "重新開始", value: "restart", className: "btn" },
        { label: "儲存並回主選單", value: "menu", className: "btn" },
        { label: "結束本局", value: "finish", className: "btn btn-danger" },
      ],
    });
    this.paused = false;
    if (choice === "resume" || choice === null) {
      this.engine.resume();
      this.focusInput();
    }
    if (choice === "restart") this.restart();
    if (choice === "menu") this.app.go("menu");
    if (choice === "finish") this.engine.finish("manual");
  }

  restart() {
    const settings = this.engine.settings;
    this.app.state.clearSavedGame();
    this.engine.stop();
    this.app.go("game", { settings });
  }

  handleCombo(milestone) {
    if (!this.app.state.getSettings().enableComboEffect) return;
    this.app.showToast(`Combo x${milestone}`, "success", 1200);
  }

  finish(result) {
    this.app.state.clearSavedGame();
    this.app.state.setCurrentResult(result);
    const { isNewRecord } = this.app.state.pushHistory(result);
    if (isNewRecord) {
      this.app.audio.playSfx("newRecord");
      result.isNewRecord = true;
    }
    this.app.go("result", { result });
  }

  languageLabel(language) {
    return { en: "English", zh: "中文", num: "數字", mixed: "混合", hira: "平假名", kata: "片假名" }[language] ?? "English";
  }

  inputLang(language) {
    return ["hira", "kata"].includes(language) ? "ja" : "zh-TW";
  }

  unmount() {
    this.engine?.stop();
    this.cleanup.forEach((fn) => fn());
    this.cleanup = [];
  }
}


/* js/screens/ResultScreen.js */


class ResultScreen {
  constructor(app) {
    this.app = app;
    this.root = null;
  }

  mount({ result = null } = {}) {
    const activeResult = result ?? this.app.state.currentResult;
    this.root = document.createElement("section");
    this.root.id = "result";
    this.root.className = "screen result-screen";

    if (!activeResult) {
      this.root.innerHTML = `
        <div class="panel panel-pad">
          <h1 class="screen-title">尚無結果</h1>
          <p class="muted">先完成一場遊戲即可查看統計。</p>
          <button class="btn btn-primary" type="button" data-action="menu" style="margin-top: var(--space-4)">回主選單</button>
        </div>
      `;
    } else {
      const shareText = this.buildShareText(activeResult);
      this.root.innerHTML = `
        <div class="result-hero">
          <section class="panel result-rank">
            <span class="rank-letter">${activeResult.rank}</span>
            <div>
              <h1 class="screen-title">${activeResult.isNewRecord ? "新紀錄" : "本局完成"}</h1>
              <p class="muted">${DifficultyManager.label(activeResult.settings.difficulty)} / ${formatDate(activeResult.finishedAt)}</p>
            </div>
            <div class="toolbar">
              <button class="btn btn-primary" type="button" data-action="retry">再玩一次</button>
              <button class="btn" type="button" data-action="new">重新設定</button>
              <button class="btn btn-ghost" type="button" data-action="menu">主選單</button>
            </div>
          </section>

          <section class="panel panel-pad">
            <div class="score-grid">
              <div class="score-tile"><span class="score-label">WPM</span><strong class="score-value">${activeResult.wpm}</strong></div>
              <div class="score-tile"><span class="score-label">準確率</span><strong class="score-value">${formatPercent(activeResult.accuracy)}</strong></div>
              <div class="score-tile"><span class="score-label">分數</span><strong class="score-value">${activeResult.score}</strong></div>
              <div class="score-tile"><span class="score-label">最高連擊</span><strong class="score-value">${activeResult.maxCombo}</strong></div>
              <div class="score-tile"><span class="score-label">完成字</span><strong class="score-value">${activeResult.wordsCompleted}</strong></div>
              <div class="score-tile"><span class="score-label">正確字元</span><strong class="score-value">${activeResult.correctChars}</strong></div>
              <div class="score-tile"><span class="score-label">錯誤字元</span><strong class="score-value">${activeResult.wrongChars}</strong></div>
              <div class="score-tile"><span class="score-label">用時</span><strong class="score-value">${formatTime(activeResult.elapsedSeconds)}</strong></div>
            </div>
            <div class="share-box" style="margin-top: var(--space-5)" data-field="share">${shareText}</div>
            <div class="toolbar" style="margin-top: var(--space-4)">
              <button class="btn" type="button" data-action="share">複製戰績</button>
              <button class="btn" type="button" data-action="settings">設定</button>
            </div>
          </section>
        </div>
      `;
    }

    this.root.addEventListener("click", this.handleClick);
    return this.root;
  }

  buildShareText(result) {
    return `Typing Master ${result.rank} Rank | ${result.wpm} WPM | ${formatNumber(result.accuracy, 1)}% | ${result.score} pts | ${DifficultyManager.label(result.settings.difficulty)}`;
  }

  handleClick = async (event) => {
    const action = event.target.closest("[data-action]")?.dataset.action;
    if (!action) return;
    this.app.audio.playSfx("buttonClick");
    const result = this.app.state.currentResult;
    if (action === "menu") this.app.go("menu");
    if (action === "settings") this.app.go("settings");
    if (action === "retry" && result) this.app.go("game", { settings: result.settings });
    if (action === "new") this.app.go("menu");
    if (action === "share") {
      const text = this.root.querySelector("[data-field='share']").textContent;
      try {
        await navigator.clipboard.writeText(text);
        this.app.showToast("已複製戰績", "success");
      } catch {
        this.app.showToast("瀏覽器不允許直接複製，請手動選取戰績文字", "warning");
      }
    }
  };

  unmount() {
    this.root?.removeEventListener("click", this.handleClick);
  }
}


